function a(){const n=document.querySelectorAll("[data-split-text]");n.length&&n.forEach(e=>{const o=e.textContent.trim();e.innerHTML="",o.split("").forEach(s=>{const t=document.createElement("span");s===" "?(t.classList.add("space"),t.innerHTML="&nbsp;"):t.textContent=s,e.appendChild(t)})})}export{a as s};
